----------------------------协议返回--------------------------------------
--晋升 返回
function ModelGrade:OnGradeUpLevelResp(pb)
    local level = pb.level
    local exp = pb.exp
    self.gradeLevel = level
    self.gradeExp = exp
    self:OnGradeRewardListReq()
end

--领取冒险评级每日奖励 返回
function ModelGrade:OnGradeRewardResp(pb)
    local refId = pb.refId
    if not self._rewards then
        return
    end
    self._rewards[refId] = 1
    FireEvent("OnGradeRewardResp")
end

function ModelGrade:OnPlayerChangeResp(pb)
    local player = pb.player
    local gradeLevel = player.gradeLevel
    if(gradeLevel and gradeLevel > 0)then
		if self.gradeLevel and self.gradeLevel < gradeLevel then
            GF.OpenWnd("UIRiskRtUpLvl", {lvl = gradeLevel})
            FireEvent("PlayerGradeLvlUp")
		end
        self.gradeLevel = gradeLevel
        self.gradeExp = player.gradeExp
    end
end

--每日奖励状态 返回
function ModelGrade:OnGradeRewardListResp(pb)
    local rewards = pb.rewards
    self._rewards = {}
    for i, v in ipairs(rewards) do
        local refId = v.refId
        local state = v.state       --1-可领取,2-已领取
        self._rewards[refId] = state
    end
end
