function ModelGrade:GetTaskConfigList()
    local lv = self:GetGradeLevel()
    if not lv or lv < 1 then
        return nil
    end
    local list = self:GetTaskConfigListByLv(lv)
    for i, v in ipairs(list) do
        local _schedule = tonumber(v._schedule)
        local _goal = tonumber(v._goal)
        if _schedule < _goal then
            return v
        end
    end
    return nil
end

function ModelGrade:GetTaskConfigListByLv(lv)
    local ref = self:GetGradeLvRefByRefId(lv)
    local taskList = {}
    local questIdArr = string.split(ref.questId,";")
    local list = gModelQuest:GetTaskKeyList(ModelQuest.GRADE_QUEST)
    for i, v in ipairs(questIdArr) do
        local task = list[tonumber(v)]
        if task then
            table.insert(taskList,task)
        end
    end
    return taskList
end

function ModelGrade:GetGradeTaskRed()
    local lv = self:GetGradeLevel()
    if not lv or lv < 1 then
        return false
    end
    for i = 1, lv do
        local ref = gModelGrade:GetGradeLvRefByRefId(i)
        local questIdArr = string.split(ref.questId,";")
        local list = gModelQuest:GetTaskKeyList(ModelQuest.GRADE_QUEST)
        for i, v in ipairs(questIdArr) do
            local task = list[tonumber(v)]
            if task  and task._state == 1 then
                return true
            end
        end
    end
    return false
end

function ModelGrade:GetIsActivatePrivilege(privilegeId)
    local _gradeLevel = self:GetGradeLevel()
    local _gradeExp = self:GetGradeExp()
    for i = 1, _gradeLevel do
        local ref = self:GetGradeLvRefByRefId(i)
        -- if(ref)then
        --     local eventIdArr = string.split(ref.eventId,";")
        --     for k, v in ipairs(eventIdArr) do
        --         local eventArr = string.split(v,"=")
        --         if(tonumber(eventArr[1]) == privilegeId)then
        --             if(i == _gradeLevel and _gradeExp >= tonumber(eventArr[2]) or i < _gradeLevel)then
        --                 return true
        --             end
        --         end
        --     end
        -- end

        local taskList = self:GetTaskConfigListByRef(i, ref)
        if taskList then
            for _, v in ipairs(taskList) do
                local ref = gModelQuest:GetTaskConfig(tonumber(v._refId))
                if tonumber(ref.SysReward) == privilegeId and v._state == 2 then
                    return true
                end
            end
        end
    end
    return false
end

function ModelGrade:GetTaskConfigListByRef(lv, ref)
	local taskList = {}
	local questIdArr = string.split(ref.questId, ";")
	local list = gModelQuest:GetTaskKeyList(ModelQuest.GRADE_QUEST)
	for i, v in ipairs(questIdArr) do
		local task = list[tonumber(v)]
		if task then
			table.insert(taskList, task)
		else
            local _gradeLevel = self:GetGradeLevel()
			local ref = gModelQuest:GetTaskConfig(tonumber(v))
			local finishCondArr = string.split(ref.finishCond, "=")
			local state = lv > _gradeLevel and 0 or 2
			local schedule, goal
			if ref.questProgressType == 1 then
				schedule, goal = lv <= _gradeLevel and "1" or "0", "1"
			else
				local strArr = string.split(finishCondArr[3], ",")
				local len = #strArr
				schedule, goal = lv <= _gradeLevel and strArr[len] or "0", strArr[len]
			end
			local task = {
				_refId = ref.refId,
				_schedule = schedule,
				_sort = ref._sort,
				_state = state,
				_goal = goal
			}
			table.insert(taskList, task)
		end
	end
	return taskList
end

function ModelGrade:GetHeroResonanceEffectValue()
    local subTimeNum = 0
    local sysbuffHeroRes = gModelGeneral:GetHeroResonanceList()
    for k,v in pairs(sysbuffHeroRes) do
        local status = self:GetIsActivatePrivilege(k)
        if status then
            subTimeNum = subTimeNum + tonumber(v.effectValue) * 3600
        end
    end
    return subTimeNum
end
