function ModelGrade:GetPrivilegeListByLv(lv)
    local lv = lv or self:GetGradeLevel()
    local list = {}
    local ref = self:GetGradeLvRefByRefId(lv)
    local eventIdArr  = string.split(ref.eventId,";")
    for i, v in ipairs(eventIdArr) do
        local arr =  string.split(v,"=")
        local info = {
            id = tonumber(arr[1]),
            value = tonumber(arr[2])
        }
        table.insert(list,info)
    end
    return list
end

function ModelGrade:GetPrivilegeEffRefs(privilegeType)
    local effIdList = gModelGeneral:GetSysEffListByType(privilegeType)
    local list = {}
    for k,v in ipairs(effIdList) do
        local refId = v.refId
        local isActive = gModelGrade:GetIsActivatePrivilege(refId)
        if isActive then
            local cfg = v
            table.insert(list,cfg)
        end
    end
    return list
end

function ModelGrade:GetPrivilegeEff(privilegeType)
    local effIdList = self:GetPrivilegeEffRefs(privilegeType)
    local maxAddExplorePoint = 0
    for k,v in ipairs(effIdList) do
        local value = tonumber( v.effectValue)
        maxAddExplorePoint = maxAddExplorePoint + value
    end
    return maxAddExplorePoint or 0
end
function ModelGrade:GetGradeLvConfigRefByKey(key)
    return GameTable.GradeLvConfigRef[key]
end
