function ModelGrade:SetIsShow(bool)--设置是否显示主界面
    local value = bool and 1 or 0
    LPlayerPrefs.SetGradeToogle(tostring(value))
    FireEvent(EventNames.SHOW_MAIN_GRADE)
end
function ModelGrade:GetIsShow()--是否显示主界面
    if not self:GetIsOpened() then
        return false
    end
    local gradeToogle = LPlayerPrefs.gradeToogle
    if not gradeToogle or gradeToogle == "" or gradeToogle == "1" then
        return true
    end
    return false
end
function ModelGrade:GetRewardUp()
    local _gradeLevel = self:GetGradeLevel()
    local list = self:GetGradeLvRef()
    local nexAwardItem = nil
    local rewardUp = ""
    for i, v in ipairs(list) do
        if v.rewardSign == 1 and v.refId >= _gradeLevel then
            nexAwardItem = v
            break
        end
    end

    if nexAwardItem then
        rewardUp = gModelPlayer:GetGradeLvRefRewardUp(nexAwardItem)
    end
    return rewardUp
end
